// // This module performs an 8-bit multiplication and outputs a 16-bit result when enabled.
module top_module(
    input  wire        clk,
    input  wire        ena,
    input  wire [ 7:0] A,
    input  wire [ 7:0] B,
    output reg  [15:0] Z
);always @(posedge clk)
        if (ena) Z <= A * B;

endmodule
